(function(){var cfg=window.FQTermFeatured||{};if(!cfg.ajaxUrl||!cfg.nonce){return}var post=function(params){return fetch(cfg.ajaxUrl,{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=UTF-8"},body:new URLSearchParams(params).toString()}).then(function(r){return r.json()})};document.addEventListener("change",function(event){var el=event.target;if(!(el instanceof HTMLInputElement)||!el.classList.contains("fq-term-featured-toggle")){return}var termId=el.getAttribute("data-term-id")||"";var taxonomy=el.getAttribute("data-taxonomy")||"";var checked=el.checked;el.disabled=true;post({action:"fq_toggle_featured_term",nonce:cfg.nonce,term_id:termId,taxonomy:taxonomy,value:checked?"1":""}).then(function(res){if(!res||!res.success){throw new Error("request_failed")}}).catch(function(){el.checked=!checked}).finally(function(){el.disabled=false})})})();
